class Solution:
    def sumPrefixScores(self, words):
        from collections import Counter
        prefix_count = Counter()
        for w in words:
            for i in range(1, len(w) + 1):
                prefix_count[w[:i]] += 1
        result = []
        for w in words:
            total = 0
            for i in range(1, len(w) + 1):
                total += prefix_count[w[:i]]
            result.append(total)
        return result

