class Solution:
    def sumPrefixScores(self, words):
        children = [{}]
        count = [0]
        for w in words:
            node = 0
            for ch in w:
                if ch not in children[node]:
                    children[node][ch] = len(children)
                    children.append({})
                    count.append(0)
                node = children[node][ch]
                count[node] += 1
        result = []
        for w in words:
            node = 0
            total = 0
            for ch in w:
                node = children[node][ch]
                total += count[node]
            result.append(total)
        return result

