var sumPrefixScores = function(words) {
    const children = [new Map()];
    const count = [0];
    for (const w of words) {
        let node = 0;
        for (const ch of w) {
            if (!children[node].has(ch)) {
                children[node].set(ch, children.length);
                children.push(new Map());
                count.push(0);
            }
            node = children[node].get(ch);
            count[node]++;
        }
    }
    const result = [];
    for (const w of words) {
        let node = 0, total = 0;
        for (const ch of w) {
            node = children[node].get(ch);
            total += count[node];
        }
        result.push(total);
    }
    return result;
};
